class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def build_tree(level_order):
    if not level_order or level_order[0] == 'null':
        return None

    nodes = [None if val == 'null' else TreeNode(int(val)) for val in level_order]
    child_index = 1
    for i in range(len(nodes)):
        if nodes[i] is not None:
            if child_index < len(nodes):
                nodes[i].left = nodes[child_index]
                child_index += 1
            if child_index < len(nodes):
                nodes[i].right = nodes[child_index]
                child_index += 1
    return nodes[0]

def maximumDepthOfBinaryTree(data):
    level_order = data.split()
    root = build_tree(level_order)

    def max_depth(node):
        if not node:
            return 0
        left_depth = max_depth(node.left)
        right_depth = max_depth(node.right)
        return max(left_depth, right_depth) + 1

    return max_depth(root)

