package main

import "container/list"

type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func maximumDepthOfBinaryTree(root *TreeNode) int {
    if root == nil {
        return 0
    }

    queue := list.New()
    queue.PushBack(root)
    depth := 0

    for queue.Len() > 0 {
        depth++
        levelSize := queue.Len()

        for i := 0; i < levelSize; i++ {
            node := queue.Remove(queue.Front()).(*TreeNode)
            if node.Left != nil {
                queue.PushBack(node.Left)
            }
            if node.Right != nil {
                queue.PushBack(node.Right)
            }
        }
    }

    return depth
}

